{
  "mode": "method",
  "tests": [
    {
      "name": "valid_scorecard_submission",
      "input": {
        "scorecard_data": {
          "options": ["Option A", "Option B", "Option C"],
          "selected_option": "Option A"
        }
      },
      "output": "success",
      "notes": "Valid submission with correct options should return success."
    },
    {
      "name": "missing_selected_option",
      "input": {
        "scorecard_data": {
          "options": ["Option A", "Option B", "Option C"],
          "selected_option": null
        }
      },
      "output": "error: selected option is required",
      "notes": "Submission without a selected option should return an error."
    },
    {
      "name": "empty_options_list",
      "input": {
        "scorecard_data": {
          "options": [],
          "selected_option": "Option A"
        }
      },
      "output": "error: options list cannot be empty",
      "notes": "Submission with an empty options list should return an error."
    },
    {
      "name": "invalid_selected_option",
      "input": {
        "scorecard_data": {
          "options": ["Option A", "Option B"],
          "selected_option": "Option C"
        }
      },
      "output": "error: selected option is not valid",
      "notes": "Submission with an invalid selected option should return an error."
    },
    {
      "name": "duplicate_options",
      "input": {
        "scorecard_data": {
          "options": ["Option A", "Option A", "Option B"],
          "selected_option": "Option A"
        }
      },
      "output": "success",
      "notes": "Duplicate options should still allow a valid submission."
    },
    {
      "name": "large_options_list",
      "input": {
        "scorecard_data": {
          "options": ["Option " + i for i in range(1000)],
          "selected_option": "Option 500"
        }
      },
      "output": "success",
      "notes": "Large options list should still process correctly."
    },
    {
      "name": "no_options_provided",
      "input": {
        "scorecard_data": {}
      },
      "output": "error: options and selected option are required",
      "notes": "Submission with no data should return an error."
    },
    {
      "name": "valid_scorecard_with_additional_fields",
      "input": {
        "scorecard_data": {
          "options": ["Option A", "Option B"],
          "selected_option": "Option A",
          "additional_field": "extra data"
        }
      },
      "output": "success",
      "notes": "Additional fields should not affect the validity of the submission."
    }
  ],
  "assumptions": "The scorecard_data structure is consistent with the expected format.",
  "notes": "Ensure that all edge cases are covered to validate robustness."
}
